namespace sv_3349a2a97a3b49949ea16703822a8cf1.Services;

/// <summary>
/// Scoped (per-circuit) state that tracks the currently selected warehouse
/// and notifies subscribers when the selection changes.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
        ("WH-D", "Warehouse D"),
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _selectedWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId) return;
        _selectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_3349a2a97a3b49949ea16703822a8cf1.Services;

/// <summary>
/// Scoped (per-circuit) service that simulates a low-stock database query
/// and provides cross-component notification when the alert count changes.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    /// <summary>
    /// Fired after <see cref="GetLowStockCountAsync"/> returns, so that
    /// every subscribed component can re-render — not just the caller.
    /// </summary>
    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call
        var count = _random.Next(0, 16);
        CurrentAlertCount = count;
        OnAlertCountChanged?.Invoke();
        return Task.FromResult(count);
    }
}

@using sv_3349a2a97a3b49949ea16703822a8cf1.Services
@inject WarehouseState WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<div class="warehouse-selector">
    <label for="warehouse-select" class="form-label text-white mb-0 me-2">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            value="@WarehouseState.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var warehouseId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(warehouseId))
        {
            WarehouseState.SetWarehouse(warehouseId);
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_3349a2a97a3b49949ea16703822a8cf1.Services
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2" title="Low-stock items">
        @AlertService.CurrentAlertCount
    </span>
}
else
{
    <span class="badge bg-success rounded-pill ms-2" title="No low-stock alerts">
        0
    </span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnCountChanged;
    }

    private void OnCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnCountChanged;
    }
}

@page "/dashboard"
@using sv_3349a2a97a3b49949ea16703822a8cf1.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard — @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Currently viewing: <strong>@WarehouseState.SelectedWarehouseName</strong>
            <small class="text-muted">(@WarehouseState.SelectedWarehouseId)</small>
        </h5>
    </div>
</div>

<div class="row">
    <div class="col-md-4">
        <div class="card text-white @(_alertCount > 5 ? "bg-danger" : _alertCount > 0 ? "bg-warning" : "bg-success") mb-3">
            <div class="card-body text-center">
                <h2 class="card-title display-4">@_alertCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="card mb-3">
            <div class="card-header">Polling Status</div>
            <div class="card-body">
                <p>
                    <span class="badge bg-info">Auto-refresh</span>
                    Polling every <strong>10 seconds</strong> for warehouse
                    <strong>@WarehouseState.SelectedWarehouseName</strong>.
                </p>
                @if (_lastChecked.HasValue)
                {
                    <p class="text-muted mb-0">
                        Last checked: @_lastChecked.Value.ToString("HH:mm:ss")
                    </p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int _alertCount;
    private DateTime? _lastChecked;
    private Timer? _pollingTimer;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override async Task OnInitializedAsync()
    {
        // Initial fetch
        await PollAlerts();

        // Start polling every 10 seconds
        _pollingTimer = new Timer(async _ =>
        {
            await PollAlerts();
            await InvokeAsync(StateHasChanged);
        }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
    }

    private async Task PollAlerts()
    {
        _alertCount = await AlertService.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);
        _lastChecked = DateTime.Now;
    }

    private async void OnWarehouseChanged()
    {
        // Immediately re-poll when warehouse changes
        await PollAlerts();
        await InvokeAsync(StateHasChanged);
    }

    private void OnAlertCountChanged()
    {
        _alertCount = AlertService.CurrentAlertCount;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _pollingTimer?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

