@page "/dashboard"
@using sv_3349a2a97a3b49949ea16703822a8cf1.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard — @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Currently viewing: <strong>@WarehouseState.SelectedWarehouseName</strong>
            <small class="text-muted">(@WarehouseState.SelectedWarehouseId)</small>
        </h5>
    </div>
</div>

<div class="row">
    <div class="col-md-4">
        <div class="card text-white @(_alertCount > 5 ? "bg-danger" : _alertCount > 0 ? "bg-warning" : "bg-success") mb-3">
            <div class="card-body text-center">
                <h2 class="card-title display-4">@_alertCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="card mb-3">
            <div class="card-header">Polling Status</div>
            <div class="card-body">
                <p>
                    <span class="badge bg-info">Auto-refresh</span>
                    Polling every <strong>10 seconds</strong> for warehouse
                    <strong>@WarehouseState.SelectedWarehouseName</strong>.
                </p>
                @if (_lastChecked.HasValue)
                {
                    <p class="text-muted mb-0">
                        Last checked: @_lastChecked.Value.ToString("HH:mm:ss")
                    </p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int _alertCount;
    private DateTime? _lastChecked;
    private Timer? _pollingTimer;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override async Task OnInitializedAsync()
    {
        // Initial fetch
        await PollAlerts();

        // Start polling every 10 seconds
        _pollingTimer = new Timer(async _ =>
        {
            await PollAlerts();
            await InvokeAsync(StateHasChanged);
        }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
    }

    private async Task PollAlerts()
    {
        _alertCount = await AlertService.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);
        _lastChecked = DateTime.Now;
    }

    private async void OnWarehouseChanged()
    {
        // Immediately re-poll when warehouse changes
        await PollAlerts();
        await InvokeAsync(StateHasChanged);
    }

    private void OnAlertCountChanged()
    {
        _alertCount = AlertService.CurrentAlertCount;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _pollingTimer?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

